const n = parseInt(process.argv[2]);
const perm1 = Array.from({length: n}, (_, i) => i);
const count = new Array(n).fill(0);
let maxFlips = 0, checksum = 0, permCount = 0, r = n;
outer: while (true) {
    while (r > 1) { count[r-1] = r; r--; }
    const perm = [...perm1];
    let flips = 0;
    while (perm[0] !== 0) {
        const k = perm[0] + 1;
        for (let i = 0; i < k >> 1; i++) { const t = perm[i]; perm[i] = perm[k-1-i]; perm[k-1-i] = t; }
        flips++;
    }
    if (flips > maxFlips) maxFlips = flips;
    checksum += (permCount % 2 === 0) ? flips : -flips;
    permCount++;
    while (true) {
        if (r === n) break outer;
        const p0 = perm1[0];
        for (let i = 0; i < r; i++) perm1[i] = perm1[i+1];
        perm1[r] = p0;
        if (--count[r] > 0) break;
        r++;
    }
}
console.log(checksum + "\n" + maxFlips);

function siftDown(arr, start, end) {
    let root = start;
    while (2 * root + 1 <= end) {
        let child = 2 * root + 1;
        let swap = root;
        if (arr[swap] < arr[child]) swap = child;
        if (child + 1 <= end && arr[swap] < arr[child + 1]) swap = child + 1;
        if (swap === root) return;
        [arr[root], arr[swap]] = [arr[swap], arr[root]];
        root = swap;
    }
}
const n = parseInt(process.argv[2]);
const arr = new Array(n);
let seed = 42;
for (let i = 0; i < n; i++) { seed = ((Math.imul(seed, 1103515245) + 12345) >>> 0) % 2147483648; arr[i] = (seed>>16)&0x7fff; }
for (let s = Math.floor((n-2)/2); s >= 0; s--) siftDown(arr, s, n-1);
for (let end = n-1; end > 0; end--) { [arr[0], arr[end]] = [arr[end], arr[0]]; siftDown(arr, 0, end-1); }
let checksum = 0;
for (const v of arr) checksum = (checksum + v) % 1000000007;
console.log(`${arr[0]} ${arr[n-1]} ${checksum}`);

function mergeSort(arr) {
    if (arr.length < 2) return arr;
    const mid = Math.floor(arr.length / 2);
    const left = mergeSort(arr.slice(0, mid));
    const right = mergeSort(arr.slice(mid));
    const result = [];
    let i = 0, j = 0;
    while (i < left.length && j < right.length) {
        if (left[i] <= right[j]) result.push(left[i++]);
        else result.push(right[j++]);
    }
    while (i < left.length) result.push(left[i++]);
    while (j < right.length) result.push(right[j++]);
    return result;
}
